import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { gradeApi } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { createSimulationClient } from '../../services/websocket';

const PASS_MARK = 10;

// ── Calculation helpers (mirror of backend logic) ─────────────────────────

const round2 = (v) => Math.round(v * 100) / 100;

const subjectAvg = (g, cc, exam, tp) => {
  if (cc === '' || exam === '') return null;
  const ccV = parseFloat(cc) || 0;
  const exV = parseFloat(exam) || 0;
  const tpV = (g.tpWeight > 0 && tp !== '') ? (parseFloat(tp) || 0) : 0;
  return round2((g.ccWeight / 100) * ccV + (g.examWeight / 100) * exV + (g.tpWeight / 100) * tpV);
};

const requiredExam = (g, cc, tp) => {
  if (cc === '') return null;
  const ccV = parseFloat(cc) || 0;
  const tpV = (g.tpWeight > 0 && tp !== '') ? (parseFloat(tp) || 0) : 0;
  const tpPart = (g.tpWeight / 100) * tpV;
  const req = (PASS_MARK - (g.ccWeight / 100) * ccV - tpPart) / (g.examWeight / 100);
  if (req > 20) return 'IMPOSSIBLE';
  if (req <= 0) return 'ALREADY_VALIDATED';
  return req.toFixed(2);
};

const moduleAvgFromSubjects = (subjects) => {
  if (subjects.some((s) => s.avg == null)) return null;
  const totalCoeff = subjects.reduce((s, x) => s + x.coeff, 0);
  if (totalCoeff === 0) return null;
  return round2(subjects.reduce((s, x) => s + x.avg * x.coeff, 0) / totalCoeff);
};

const semesterAvgFromModules = (modules) => {
  const withAvg = modules.filter((m) => m.avg != null);
  if (withAvg.length === 0) return null;
  const totalCred = withAvg.reduce((s, m) => s + m.credits, 0);
  if (totalCred === 0) return null;
  return round2(withAvg.reduce((s, m) => s + m.avg * m.credits, 0) / totalCred);
};

// ── Group flat GradeDTO list into semester→module hierarchy ───────────────

function buildHierarchy(grades, localMarks) {
  const bySemester = {};
  for (const g of grades) {
    const sem = g.semester;
    if (!bySemester[sem]) bySemester[sem] = {};
    const modKey = g.parentModuleName && g.parentModuleName.trim() ? g.parentModuleName : g.moduleName;
    if (!bySemester[sem][modKey]) bySemester[sem][modKey] = [];
    bySemester[sem][modKey].push(g);
  }

  return Object.keys(bySemester)
    .sort((a, b) => Number(a) - Number(b))
    .map((sem) => {
      const moduleMap = bySemester[sem];
      const modules = Object.entries(moduleMap).map(([modName, subjects]) => {
        const subjectData = subjects.map((g) => {
          const local = localMarks[g.moduleCode] || {};
          const cc   = local.cc   !== undefined ? local.cc   : (g.ccMark   != null ? String(g.ccMark)   : '');
          const exam = local.exam !== undefined ? local.exam : (g.examMark != null ? String(g.examMark) : '');
          const tp   = local.tp   !== undefined ? local.tp   : (g.tpMark   != null ? String(g.tpMark)   : '');
          const avg  = subjectAvg(g, cc, exam, tp);
          const req  = requiredExam(g, cc, tp);
          return { g, cc, exam, tp, avg, req, coeff: g.coefficient };
        });

        const modSubjects = subjectData.map((s) => ({ avg: s.avg, coeff: s.coeff }));
        const avg = moduleAvgFromSubjects(modSubjects);
        const credits = subjects.reduce((s, g) => s + g.credits, 0);
        return { modName, subjects: subjectData, avg, credits, passed: avg != null && avg >= PASS_MARK };
      });

      const semAvg = semesterAvgFromModules(modules.map((m) => ({ avg: m.avg, credits: m.credits })));
      const earnedCredits = modules.filter((m) => m.passed).reduce((s, m) => s + m.credits, 0);
      const totalCredits  = modules.reduce((s, m) => s + m.credits, 0);

      return { sem: Number(sem), modules, semAvg, earnedCredits, totalCredits };
    });
}

// ── Sub-components ────────────────────────────────────────────────────────

const markColor = (v) =>
  v == null ? 'text-slate-400' : v >= 14 ? 'text-green-600' : v >= PASS_MARK ? 'text-blue-600' : 'text-red-500';

const AvgBadge = ({ avg, size = 'sm' }) => {
  if (avg == null) return <span className="text-slate-400 text-xs">—</span>;
  const passed = avg >= PASS_MARK;
  const cls = passed ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700';
  const textCls = size === 'lg' ? 'text-base font-bold' : 'text-sm font-semibold';
  return (
    <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full ${cls} ${textCls}`}>
      {avg.toFixed(2)}/20 {passed ? '✓' : '✗'}
    </span>
  );
};

const GradeInput = ({ label, value, onChange, weight, disabled }) => (
  <div className="flex items-center gap-2">
    <span className="text-xs font-semibold text-slate-500 w-9 shrink-0">{label}</span>
    <input
      type="number" min="0" max="20" step="0.25"
      value={value}
      onChange={(e) => onChange(e.target.value)}
      disabled={disabled}
      placeholder="—"
      className="w-16 text-center text-sm border border-slate-200 rounded-lg py-1 focus:outline-none focus:ring-2 focus:ring-blue-400 bg-white disabled:bg-slate-50 disabled:opacity-60 disabled:cursor-not-allowed"
    />
    <span className="text-xs text-slate-400">/20</span>
    <span className="ml-auto text-xs text-slate-400">{weight}%</span>
  </div>
);

const SubjectCard = ({ subjectData, grade, simMode, onMarkChange, saving, onSave }) => {
  const { g, cc, exam, tp, avg, req } = subjectData;
  const hasTp = g.tpWeight > 0;
  const isOfficial = g.adminEntered && !simMode;
  const allFilled = cc !== '' && exam !== '' && (!hasTp || tp !== '');
  const passed = avg != null && avg >= PASS_MARK;

  return (
    <div className={`rounded-xl border bg-white shadow-sm overflow-hidden ${
      avg == null ? 'border-slate-200'
      : passed    ? 'border-green-200'
                  : 'border-red-200'
    }`}>
      <div className="flex items-center justify-between px-4 py-2.5 bg-slate-50/60 border-b border-slate-100">
        <div className="flex items-center gap-2 min-w-0">
          <span className="text-sm font-semibold text-slate-800 truncate">{g.moduleName}</span>
          {g.adminEntered && !simMode && (
            <span className="px-1.5 py-0.5 rounded text-xs font-bold bg-blue-100 text-blue-700 shrink-0">Official</span>
          )}
          {simMode && (
            <span className="px-1.5 py-0.5 rounded text-xs font-bold bg-amber-100 text-amber-700 shrink-0">Sim</span>
          )}
        </div>
        <div className="flex items-center gap-2 shrink-0">
          <span className="text-xs text-slate-400">Coeff {g.coefficient}</span>
          <AvgBadge avg={avg} />
        </div>
      </div>

      <div className="px-4 py-3 space-y-2">
        <GradeInput label="CC"   value={cc}   onChange={(v) => onMarkChange(g.moduleCode, 'cc', v)}   weight={g.ccWeight}   disabled={isOfficial} />
        <GradeInput label="Exam" value={exam} onChange={(v) => onMarkChange(g.moduleCode, 'exam', v)} weight={g.examWeight} disabled={isOfficial} />
        {hasTp && (
          <GradeInput label="TP" value={tp} onChange={(v) => onMarkChange(g.moduleCode, 'tp', v)} weight={g.tpWeight} disabled={isOfficial} />
        )}

        {req === 'IMPOSSIBLE' && !isOfficial && (
          <p className="text-xs text-red-600 flex items-center gap-1">
            <span>✗</span> Unattainable — cannot pass with current CC{hasTp ? '/TP' : ''}
          </p>
        )}
        {req === 'ALREADY_VALIDATED' && !isOfficial && (
          <p className="text-xs text-green-600 flex items-center gap-1">
            <span>✓</span> Already validated — CC{hasTp ? '/TP' : ''} guarantees ≥ 10
          </p>
        )}
        {req && req !== 'IMPOSSIBLE' && req !== 'ALREADY_VALIDATED' && !isOfficial && !passed && (
          <p className="text-xs text-amber-600 flex items-center gap-1">
            <span>⚠</span> Min exam to pass: <strong>{req}/20</strong>
          </p>
        )}
      </div>

      {!simMode && !isOfficial && (
        <div className="px-4 py-2 border-t border-slate-100">
          <button
            onClick={() => onSave(g.moduleCode, { moduleCode: g.moduleCode, ccMark: parseFloat(cc), examMark: parseFloat(exam), tpMark: hasTp ? parseFloat(tp) : undefined })}
            disabled={!allFilled || saving}
            className="w-full text-xs font-semibold bg-blue-600 hover:bg-blue-700 disabled:bg-slate-200 disabled:text-slate-400 text-white py-1.5 rounded-lg transition"
          >
            {saving ? 'Saving…' : 'Save'}
          </button>
        </div>
      )}
    </div>
  );
};

// ── Main page ─────────────────────────────────────────────────────────────

const GradesPage = () => {
  const { user } = useAuth();

  const [grades, setGrades]       = useState([]);
  const [loading, setLoading]     = useState(true);
  const [savingId, setSavingId]   = useState(null);
  const [feedback, setFeedback]   = useState(null);
  const [semester, setSemester]   = useState('all');

  // Per-subject local mark overrides (used in both normal + sim mode)
  const [localMarks, setLocalMarks] = useState({});

  // Simulation mode state
  const [simMode, setSimMode]           = useState(false);
  const [simResult, setSimResult]       = useState(null);
  const [wsConnected, setWsConnected]   = useState(false);
  const wsRef                           = useRef(null);
  const debounceRef                     = useRef(null);

  // ── Load saved grades ───────────────────────────────────────────────────
  const load = useCallback(() => {
    setLoading(true);
    gradeApi.myGrades()
      .then(({ data }) => setGrades(data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { load(); }, [load]);

  // ── Simulation WebSocket lifecycle ──────────────────────────────────────
  useEffect(() => {
    if (!simMode || !user?.email) return;

    const ws = createSimulationClient(user.email, (result) => {
      setSimResult(result);
    });
    wsRef.current = ws;
    setWsConnected(true);

    return () => {
      ws.disconnect();
      wsRef.current = null;
      setWsConnected(false);
      setSimResult(null);
    };
  }, [simMode, user]);

  // ── Debounced send when marks change in sim mode ────────────────────────
  useEffect(() => {
    if (!simMode || !wsRef.current) return;
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      const gradesToSend = grades.map((g) => {
        const local = localMarks[g.moduleCode] || {};
        return {
          moduleCode: g.moduleCode,
          ccMark:   parseFloat(local.cc   !== undefined ? local.cc   : g.ccMark)   || null,
          examMark: parseFloat(local.exam !== undefined ? local.exam : g.examMark) || null,
          tpMark:   g.tpWeight > 0 ? (parseFloat(local.tp !== undefined ? local.tp : g.tpMark) || null) : null,
        };
      }).filter((g) => g.ccMark != null || g.examMark != null);

      if (gradesToSend.length > 0) wsRef.current.send(gradesToSend);
    }, 350);

    return () => clearTimeout(debounceRef.current);
  }, [simMode, localMarks, grades]);

  // ── Mark change handler ─────────────────────────────────────────────────
  const handleMarkChange = (moduleCode, field, value) => {
    setLocalMarks((prev) => ({ ...prev, [moduleCode]: { ...prev[moduleCode], [field]: value } }));
  };

  // ── Save (normal mode only) ─────────────────────────────────────────────
  const notify = (msg, type = 'success') => {
    setFeedback({ msg, type });
    setTimeout(() => setFeedback(null), 3000);
  };

  const handleSave = async (moduleCode, payload) => {
    setSavingId(moduleCode);
    try {
      const { data } = await gradeApi.enterMyGrade(payload);
      setGrades((prev) => prev.map((g) => g.moduleCode === moduleCode ? data : g));
      setLocalMarks((prev) => { const n = { ...prev }; delete n[moduleCode]; return n; });
      notify('Grades saved!');
    } catch (err) {
      notify(err.response?.data?.message || 'Failed to save grades.', 'error');
    } finally {
      setSavingId(null);
    }
  };

  // ── Build hierarchy (memoised) ──────────────────────────────────────────
  const hierarchy = useMemo(() => buildHierarchy(grades, localMarks), [grades, localMarks]);

  const filteredHierarchy = semester === 'all'
    ? hierarchy
    : hierarchy.filter((h) => h.sem === parseInt(semester));

  const semesters = hierarchy.map((h) => h.sem);

  // ── Overall summary (from sim or client-side calc) ──────────────────────
  const summary = useMemo(() => {
    if (simMode && simResult) {
      return {
        gpa:     simResult.overallGpa,
        earned:  simResult.earnedCredits,
        total:   simResult.totalCredits,
        lost:    simResult.lostCredits,
        simulated: true,
      };
    }
    const allModules = hierarchy.flatMap((h) => h.modules);
    const earned = allModules.filter((m) => m.passed).reduce((s, m) => s + m.credits, 0);
    const total  = allModules.reduce((s, m) => s + m.credits, 0);
    const lost   = allModules.filter((m) => !m.passed && m.avg != null).reduce((s, m) => s + m.credits, 0);
    const withAvg = allModules.filter((m) => m.avg != null);
    const gpa = withAvg.length === 0 ? null
      : round2(withAvg.reduce((s, m) => s + m.avg * m.credits, 0) / withAvg.reduce((s, m) => s + m.credits, 0));
    return { gpa, earned, total, lost, simulated: false };
  }, [hierarchy, simMode, simResult]);

  const yearStatus = summary.gpa == null ? null
    : summary.gpa >= PASS_MARK && summary.lost === 0 ? 'PASS'
    : summary.gpa >= PASS_MARK ? 'RATTRAPAGE'
    : 'FAIL';

  const STATUS_CFG = {
    PASS:       { bg: 'bg-green-50 border-green-200',  text: 'text-green-700',  label: 'You pass the year' },
    RATTRAPAGE: { bg: 'bg-amber-50 border-amber-200',  text: 'text-amber-700',  label: 'Rattrapage — retake failed exams' },
    FAIL:       { bg: 'bg-red-50 border-red-200',      text: 'text-red-700',    label: 'You fail the year' },
  };

  // ── Resolve simulation semester data for overlay display ─────────────────
  const simSemMap = useMemo(() => {
    if (!simResult) return {};
    return Object.fromEntries(simResult.semesters.map((s) => [s.semester, s]));
  }, [simResult]);

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">

      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">My Grades</h1>
          <p className="text-slate-500 text-sm mt-0.5">
            Weights and coefficients are configured by your department admin
          </p>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          {/* Semester filter */}
          <div className="flex items-center gap-1 bg-slate-100 rounded-xl p-1">
            <button
              onClick={() => setSemester('all')}
              className={`px-3 py-1.5 rounded-lg text-xs font-medium transition ${semester === 'all' ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
            >All</button>
            {semesters.map((s) => (
              <button key={s} onClick={() => setSemester(String(s))}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition ${semester === String(s) ? 'bg-white shadow text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>
                S{s}
              </button>
            ))}
          </div>
          {/* Simulate toggle */}
          <button
            onClick={() => setSimMode((v) => !v)}
            className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold transition ${
              simMode
                ? 'bg-amber-500 hover:bg-amber-600 text-white shadow-md'
                : 'bg-white border border-slate-200 text-slate-700 hover:bg-slate-50'
            }`}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
              <path d="M13 10V3L4 14h7v7l9-11h-7z"/>
            </svg>
            {simMode ? 'Exit Simulation' : 'Simulate'}
          </button>
        </div>
      </div>

      {/* Simulation banner */}
      {simMode && (
        <div className="flex items-center gap-3 px-4 py-3 bg-amber-50 border border-amber-200 rounded-xl">
          <div className={`w-2 h-2 rounded-full ${wsConnected ? 'bg-green-500' : 'bg-slate-400'} shrink-0`}/>
          <p className="text-sm text-amber-800 font-medium">
            {wsConnected ? 'Simulation mode active — changes are not saved. Edit any mark to see real-time recalculation.' : 'Connecting…'}
          </p>
        </div>
      )}

      {/* Toast */}
      {feedback && (
        <div className={`flex items-center gap-2 px-4 py-3 rounded-xl text-sm font-medium ${
          feedback.type === 'error' ? 'bg-red-50 border border-red-200 text-red-700' : 'bg-green-50 border border-green-200 text-green-700'
        }`}>{feedback.msg}</div>
      )}

      {/* Summary bar */}
      {summary.gpa != null && (
        <div className={`rounded-2xl border-2 p-5 ${
          simMode ? 'bg-amber-50 border-amber-200' : (yearStatus ? STATUS_CFG[yearStatus].bg : 'bg-slate-50 border-slate-200')
        }`}>
          {simMode && <p className="text-xs font-bold text-amber-600 mb-3 uppercase tracking-wide">Simulated result</p>}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            <div>
              <p className="text-xs text-slate-500 mb-1">Overall GPA</p>
              <p className={`text-2xl font-bold ${markColor(summary.gpa)}`}>
                {summary.gpa.toFixed(2)}<span className="text-sm font-normal text-slate-400">/20</span>
              </p>
            </div>
            <div>
              <p className="text-xs text-slate-500 mb-1">Credits Earned</p>
              <p className="text-2xl font-bold text-slate-800">
                {summary.earned}<span className="text-sm font-normal text-slate-400">/{summary.total}</span>
              </p>
            </div>
            <div>
              <p className="text-xs text-slate-500 mb-1">Credits Lost</p>
              <p className={`text-2xl font-bold ${summary.lost > 0 ? 'text-red-500' : 'text-slate-400'}`}>{summary.lost}</p>
            </div>
            <div>
              <p className="text-xs text-slate-500 mb-1">Year Result</p>
              {yearStatus && (
                <p className={`text-sm font-bold mt-1 ${STATUS_CFG[yearStatus].text}`}>{STATUS_CFG[yearStatus].label}</p>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Content */}
      {loading ? (
        <div className="flex justify-center py-20">
          <div className="w-8 h-8 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"/>
        </div>
      ) : filteredHierarchy.length === 0 ? (
        <div className="text-center py-16 bg-white rounded-2xl border border-slate-200">
          <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-slate-400" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
              <path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"/>
            </svg>
          </div>
          <p className="text-slate-600 font-medium">No modules configured yet</p>
          <p className="text-slate-400 text-sm mt-1">Your admin hasn't set up grade configurations for your department</p>
        </div>
      ) : (
        <div className="space-y-8">
          {filteredHierarchy.map(({ sem, modules, semAvg, earnedCredits, totalCredits }) => {
            const simSem = simSemMap[sem];
            const displaySemAvg = (simMode && simSem) ? simSem.semesterAvg : semAvg;

            return (
              <section key={sem}>
                {/* Semester header */}
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <h2 className="text-lg font-bold text-slate-800">Semester {sem}</h2>
                    <span className="text-xs text-slate-400">
                      {earnedCredits}/{totalCredits} credits
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-xs text-slate-500">Semester avg:</span>
                    <AvgBadge avg={displaySemAvg} size="lg" />
                    {simMode && displaySemAvg !== semAvg && (
                      <span className="text-xs text-amber-600 font-semibold">(sim)</span>
                    )}
                  </div>
                </div>

                {/* Module groups */}
                <div className="space-y-5">
                  {modules.map(({ modName, subjects, avg: modAvg, credits: modCred, passed: modPassed }) => {
                    const simMod = simMode && simSem
                      ? simSem.modules.find((m) => m.moduleName === modName)
                      : null;
                    const displayModAvg = (simMode && simMod) ? simMod.moduleAvg : modAvg;

                    return (
                      <div key={modName} className="bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden">
                        {/* Module header */}
                        <div className={`flex items-center justify-between px-5 py-3 border-b ${
                          displayModAvg == null ? 'border-slate-200 bg-white'
                          : displayModAvg >= PASS_MARK ? 'border-green-100 bg-green-50'
                          : 'border-red-100 bg-red-50'
                        }`}>
                          <div>
                            <h3 className="font-bold text-slate-800">{modName}</h3>
                            <p className="text-xs text-slate-400">{modCred} credits · {subjects.length} subject{subjects.length > 1 ? 's' : ''}</p>
                          </div>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-500">Module avg:</span>
                            <AvgBadge avg={displayModAvg} size="lg" />
                            {simMode && displayModAvg !== modAvg && (
                              <span className="text-xs text-amber-600 font-semibold">(sim)</span>
                            )}
                          </div>
                        </div>

                        {/* Subjects grid */}
                        <div className={`p-4 ${subjects.length > 1 ? 'grid grid-cols-1 sm:grid-cols-2 gap-3' : ''}`}>
                          {subjects.map((sd) => (
                            <SubjectCard
                              key={sd.g.moduleCode}
                              subjectData={sd}
                              grade={sd.g}
                              simMode={simMode}
                              onMarkChange={handleMarkChange}
                              saving={savingId === sd.g.moduleCode}
                              onSave={handleSave}
                            />
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </section>
            );
          })}
        </div>
      )}

      {/* Legend */}
      {!loading && filteredHierarchy.length > 0 && (
        <div className="bg-slate-50 rounded-xl border border-slate-200 px-4 py-3 text-xs text-slate-400 space-y-1">
          <p><strong className="text-slate-500">Official</strong> — Entered by admin. Read-only in normal mode.</p>
          <p><strong className="text-slate-500">Coeff</strong> — Subject coefficient used to compute the module average.</p>
          <p><strong className="text-slate-500">Simulate</strong> — Edit any marks to see what-if results in real-time (not saved).</p>
        </div>
      )}
    </div>
  );
};

export default GradesPage;
